from selenium.webdriver.support.ui import WebDriverWait
from selenium.webdriver.support import expected_conditions as EC
from selenium.common.exceptions import TimeoutException


class BasePage:
    def __init__(self, driver):
        self.driver = driver
        self.wait   = WebDriverWait(driver, 20)

    def click(self, locator):
        """Wait for element to be clickable then click it."""
        self.wait.until(EC.element_to_be_clickable(locator)).click()

    def type(self, locator, text):
        """Wait for element then clear and type into it."""
        el = self.wait.until(EC.visibility_of_element_located(locator))
        el.clear()
        el.send_keys(text)

    def get_text(self, locator):
        """Wait for element and return its visible text."""
        return self.wait.until(
            EC.visibility_of_element_located(locator)
        ).text

    def is_visible(self, locator, timeout=5):
        """Return True if element is visible within timeout."""
        try:
            WebDriverWait(self.driver, timeout).until(
                EC.visibility_of_element_located(locator)
            )
            return True
        except TimeoutException:
            return False

    def get_current_url(self): return self.driver.current_url
    def get_title(self):       return self.driver.title


from selenium.webdriver.common.by import By
from pages.base_page import BasePage


class LoginPage(BasePage):
    USERNAME_INPUT = (By.ID, "user-name")
    PASSWORD_INPUT = (By.ID, "password")
    LOGIN_BUTTON   = (By.ID, "login-button")
    ERROR_MESSAGE  = (By.CSS_SELECTOR, "[data-test='error']")

    def navigate(self):
        from config.config import Config
        self.driver.get(Config.BASE_URL)

    def login(self, username, password):
        self.type(self.USERNAME_INPUT, username)
        self.type(self.PASSWORD_INPUT, password)
        self.click(self.LOGIN_BUTTON)

    def get_error_message(self):  return self.get_text(self.ERROR_MESSAGE)
    def is_error_displayed(self): return self.is_visible(self.ERROR_MESSAGE)


from selenium.webdriver.common.by import By
from pages.base_page import BasePage


class InventoryPage(BasePage):
    PAGE_TITLE       = (By.CLASS_NAME, "title")
    INVENTORY_ITEMS  = (By.CLASS_NAME, "inventory_item")
    ITEM_NAMES       = (By.CLASS_NAME, "inventory_item_name")
    ITEM_PRICES      = (By.CLASS_NAME, "inventory_item_price")
    ADD_TO_CART_BTNS = (By.CSS_SELECTOR, "button[data-test^='add-to-cart']")
    CART_BADGE       = (By.CLASS_NAME, "shopping_cart_badge")
    CART_ICON        = (By.CLASS_NAME, "shopping_cart_link")
    SORT_DROPDOWN    = (By.CLASS_NAME, "product_sort_container")

    def get_page_title(self):   return self.get_text(self.PAGE_TITLE)
    def get_item_count(self):   return len(self.driver.find_elements(*self.INVENTORY_ITEMS))
    def get_all_item_names(self):
        return [e.text for e in self.driver.find_elements(*self.ITEM_NAMES)]
    def get_all_prices(self):
        return [float(e.text.replace("$","")) for e in self.driver.find_elements(*self.ITEM_PRICES)]
    def add_item_to_cart_by_index(self, index=0):
        self.driver.find_elements(*self.ADD_TO_CART_BTNS)[index].click()
    def add_first_item_to_cart(self): self.add_item_to_cart_by_index(0)
    def get_cart_badge_count(self):
        return int(self.get_text(self.CART_BADGE)) if self.is_visible(self.CART_BADGE) else 0
    def go_to_cart(self): self.click(self.CART_ICON)
    def sort_by(self, option):
        from selenium.webdriver.support.ui import Select
        Select(self.driver.find_element(*self.SORT_DROPDOWN)).select_by_value(option)


from selenium.webdriver.common.by import By
from pages.base_page import BasePage


class CartPage(BasePage):
    PAGE_TITLE     = (By.CLASS_NAME, "title")
    CART_ITEMS     = (By.CLASS_NAME, "cart_item")
    ITEM_NAMES     = (By.CLASS_NAME, "inventory_item_name")
    REMOVE_BUTTONS = (By.CSS_SELECTOR, "button[data-test^='remove']")
    CONTINUE_BTN   = (By.ID, "continue-shopping")
    CHECKOUT_BTN   = (By.ID, "checkout")

    def get_page_title(self):       return self.get_text(self.PAGE_TITLE)
    def get_cart_item_count(self):  return len(self.driver.find_elements(*self.CART_ITEMS))
    def get_cart_item_names(self):  return [e.text for e in self.driver.find_elements(*self.ITEM_NAMES)]
    def remove_first_item(self):    self.driver.find_elements(*self.REMOVE_BUTTONS)[0].click()
    def continue_shopping(self):    self.click(self.CONTINUE_BTN)
    def proceed_to_checkout(self):  self.click(self.CHECKOUT_BTN)
    def is_empty(self):             return self.get_cart_item_count() == 0

import time from selenium.webdriver.common.by import By from selenium.webdriver.support import expected_conditions as EC from selenium.webdriver.support.ui import WebDriverWait from pages.base_page import BasePage
class CheckoutPage(BasePage): SLOW_WAIT = 30
# Step 1 — Information PAGE_TITLE = (By.CLASS_NAME, "title") FIRST_NAME = (By.ID, "first-name") LAST_NAME = (By.ID, "last-name") POSTAL_CODE = (By.ID, "postal-code") CONTINUE_BTN = (By.ID, "continue") CANCEL_BTN = (By.ID, "cancel") ERROR_MESSAGE = (By.CSS_SELECTOR, "[data-test='error']")
# Step 2 — Overview ITEM_TOTAL = (By.CLASS_NAME, "summary_subtotal_label") TAX_LABEL = (By.CLASS_NAME, "summary_tax_label") TOTAL_LABEL = (By.CLASS_NAME, "summary_total_label") FINISH_BTN = (By.ID, "finish")
# Step 3 — Complete COMPLETE_HEADER = (By.CLASS_NAME, "complete-header") BACK_HOME_BTN = (By.ID, "back-to-products")
def get_page_title(self): return self.get_text(self.PAGE_TITLE) def get_error_message(self): return self.get_text(self.ERROR_MESSAGE) def is_error_displayed(self): return self.is_visible(self.ERROR_MESSAGE)
def enter_information(self, first, last, postal): self.type(self.FIRST_NAME, first) self.type(self.LAST_NAME, last) self.type(self.POSTAL_CODE, postal)
def click_continue(self): self.click(self.CONTINUE_BTN) def click_cancel(self): self.click(self.CANCEL_BTN)
def fill_and_continue(self, first="John", last="Doe", postal="12345"): self.enter_information(first, last, postal) time.sleep(0.5) self.click(self.CONTINUE_BTN) # Wait for FINISH button — proves Overview page loaded WebDriverWait(self.driver, self.SLOW_WAIT).until( EC.presence_of_element_located(self.FINISH_BTN))
def get_item_total(self): return float(self.get_text(self.ITEM_TOTAL).split("$")[-1]) def get_tax(self): return float(self.get_text(self.TAX_LABEL).split("$")[-1]) def get_total(self): return float(self.get_text(self.TOTAL_LABEL).split("$")[-1])
def click_finish(self): time.sleep(0.5) self.click(self.FINISH_BTN) # Wait for confirmation header — proves order completed WebDriverWait(self.driver, self.SLOW_WAIT).until( EC.visibility_of_element_located(self.COMPLETE_HEADER))
def get_confirmation_header(self): return WebDriverWait(self.driver, self.SLOW_WAIT).until( EC.visibility_of_element_located(self.COMPLETE_HEADER)).text
def click_back_home(self): self.click(self.BACK_HOME_BTN) WebDriverWait(self.driver, self.SLOW_WAIT).until( EC.presence_of_element_located((By.CLASS_NAME, "inventory_list")))

from selenium.webdriver.common.by import By from selenium.webdriver.support import expected_conditions as EC from selenium.webdriver.support.ui import WebDriverWait from pages.base_page import BasePage
class NavPage(BasePage): BURGER_MENU = (By.ID, "react-burger-menu-btn") MENU_CLOSE_BTN = (By.ID, "react-burger-cross-btn") ALL_ITEMS_LINK = (By.ID, "inventory_sidebar_link") LOGOUT_LINK = (By.ID, "logout_sidebar_link") RESET_LINK = (By.ID, "reset_sidebar_link") CART_ICON = (By.CLASS_NAME, "shopping_cart_link") CART_BADGE = (By.CLASS_NAME, "shopping_cart_badge") APP_LOGO = (By.CLASS_NAME, "app_logo")
def open_menu(self): self.click(self.BURGER_MENU) WebDriverWait(self.driver, 10).until( EC.visibility_of_element_located(self.LOGOUT_LINK))
def close_menu(self): self.click(self.MENU_CLOSE_BTN)
def logout(self): self.open_menu() self.click(self.LOGOUT_LINK) WebDriverWait(self.driver, 10).until( EC.presence_of_element_located((By.ID, "login-button")))
def go_to_all_items(self): self.open_menu() self.click(self.ALL_ITEMS_LINK)
def reset_app_state(self): self.open_menu() self.click(self.RESET_LINK) self.close_menu()
def get_cart_count(self): return int(self.get_text(self.CART_BADGE)) if self.is_visible(self.CART_BADGE) else 0
def get_app_logo_text(self): return self.get_text(self.APP_LOGO) def go_to_cart(self): self.click(self.CART_ICON)

import pytest, os, time from selenium import webdriver from selenium.webdriver.chrome.options import Options from selenium.webdriver.chrome.service import Service from webdriver_manager.chrome import ChromeDriverManager from config.config import Config
_suite_start = time.time()
def get_driver(): """Create and return a configured Chrome WebDriver.""" options = Options() if Config.HEADLESS: options.add_argument("--headless") options.add_argument("--no-sandbox") options.add_argument("--disable-dev-shm-usage") options.add_argument("--window-size=1920,1080") options.add_argument("--disable-notifications") options.add_argument("--disable-save-password-bubble") options.add_experimental_option("prefs", { "credentials_enable_service": False, "profile.password_manager_enabled": False, "profile.password_manager_leak_detection": False, }) drv = webdriver.Chrome( service=Service(ChromeDriverManager().install()), options=options ) drv.implicitly_wait(Config.IMPLICIT_WAIT) drv.maximize_window() return drv
@pytest.fixture(scope="function") def driver(): """Fresh browser per test. Auto-closes after.""" drv = get_driver() yield drv drv.quit()
@pytest.fixture(scope="function") def logged_in_driver(driver): """Driver pre-logged-in as standard_user.""" from pages.login_page import LoginPage page = LoginPage(driver) page.navigate() page.login(Config.VALID_USER, Config.PASSWORD) yield driver
@pytest.hookimpl(tryfirst=True, hookwrapper=True) def pytest_runtest_makereport(item, call): """Auto-screenshot on every test failure.""" outcome = yield report = outcome.get_result() if report.when == "call" and report.failed: driver = item.funcargs.get("driver") or \ item.funcargs.get("logged_in_driver") if driver: os.makedirs("reports/screenshots", exist_ok=True) path = f"reports/screenshots/{item.name}.png" driver.save_screenshot(path) print(f"\n📸 Screenshot saved: {path}")
def pytest_configure(config): print("\n" + "="*60) print(" 🧪 SELENIUM SUITE — saucedemo.com") print(f" 📍 Base URL : {Config.BASE_URL}") print(f" 🌐 Browser : {Config.BROWSER}") print("="*60)
def pytest_terminal_summary(terminalreporter, exitstatus, config): passed = len(terminalreporter.stats.get("passed", [])) failed = len(terminalreporter.stats.get("failed", [])) error = len(terminalreporter.stats.get("error", [])) skipped = len(terminalreporter.stats.get("skipped", [])) duration = round(time.time() - _suite_start, 2) from utils.report_helper import save_run_summary save_run_summary(passed, failed, duration) print("\n" + "="*60) print(" 📊 TEST RUN COMPLETE") print("="*60) print(f" ✅ Passed : {passed}") print(f" ❌ Failed : {failed}") print(f" ⚠️ Errors : {error}") print(f" ⏭️ Skipped : {skipped}") print(f" 📦 Total : {passed + failed + error}") print(f" ⏱️ Duration: {duration}s") print(f" 🏆 Status : {'PASS ✅' if failed == 0 else 'FAIL ❌'}") print("="*60)
